export type { Island, IslandsManifest } from './island';
export { getAllIslands, getIslandByFullPath } from './island';

export type DeviceType = 'base' | 'desktop' | 'mobile' | 'tablet' | 'webview';

export type HydrateValue = boolean | 'hydrate' | 'hydrateRoot' | 'islands';

export interface Paths {
  view: string;
  styles: string;
  client: string;
  transpiledView: string | null;
  islands: string[];
  hydrate: HydrateValue;
  canUseBootstrapPage: boolean;
}

export type PagePathsByDevice = {
  [device in DeviceType]?: Paths;
};

export interface CatchAllMetadata {
  params: string[];
  regexRoute: string | null;
}

export interface NavigablePage {
  route: string;
  isRegexRoute: boolean;
  hooks: string;
  catchAllMetadata: CatchAllMetadata | null;
  paths: PagePathsByDevice;
}

export interface HttpErrorPage {
  paths: PagePathsByDevice;
}

export interface DiscoveredNordicPages {
  hasBuild: boolean;
  baseHooksFile: string | undefined;
  discoveredNavigablePages: NavigablePage[];
  discoveredHttpErrorPages: Record<string, HttpErrorPage>;
}

/**
 * Discovers Nordic Pages and writes the discovery manifest.
 * Called once at build time and writes the discovered pages to the file `.nordic/discovery/`.
 * @param basePath - Directory path where to find the pages (defaults to process.cwd())
 */
export function discoverNordicPages(basePath?: string): void;

/**
 * Reads the discovery manifest written by discoverNordicPages.
 * Returns undefined if the manifest has not been written yet.
 */
export function getDiscoveredNordicPages(): DiscoveredNordicPages | undefined;
